+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function stripFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) {
+  if (mode === 'none') return false;
+  const node = line.includes('node:internal');
+  const superjson =
+    line.includes('src/transformer.ts') ||
+    line.includes('src/plainer.ts') ||
+    line.includes('src/index.ts');
+  return (mode === 'node' && node) ||
+    (mode === 'superjson' && superjson) ||
+    (mode === 'node_and_superjson' && (node || superjson));
+}
+
+function redact(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'none') return line;
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replaceAll(cwd, '');
+  }
+  return line.replace(/(?:[A-Za-z]:)?(?:[\\\\/][^\\s():]+)+/g, match => {
+    const parts = match.split(/[\\\\/]/);
+    return parts[parts.length - 1];
+  });
+}
+
+function stackLines(stack: string, options: NormalizedErrorStackOptions, frames: boolean): string[] {
+  let lines = (options.normalizeNewlines ? normalizeStackNewlines(stack) : stack).split('\
');
+  lines = lines.map((line, index) =>
+    index > 0 && options.trimLeadingWhitespace ? line.replace(/^\\s+/, '') : line
+  );
+  if (frames) {
+    lines = lines.filter((line, index) => index === 0 || !stripFrame(line, options.stripInternalFrames));
+    lines = lines.map(line => redact(line, options.redactPaths));
+  } else {
+    lines = lines.map(line => redact(line, options.redactPaths));
+    lines = lines.filter((line, index) => index === 0 || !stripFrame(line, options.stripInternalFrames));
+  }
+  return options.maxStackLines === undefined ? lines : lines.slice(0, options.maxStackLines);
+}
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  return stackLines(stack, options, false).join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): Array<{ raw: string }> {
+  return stackLines(stack, options, true).map(raw => ({ raw }));
+}
